/**
 * 组装云雾 request_body（Gemini generateContent）
 *
 * ✅ 支持 0~2 张参考图（达人 + 产品）
 * ✅ 防覆盖：使用 person_* / product_* 字段
 * ✅ 兜底兼容旧字段：image_b64 / mime_type
 * ✅ 强制“去场景化”：不写死地点/光线
 * ✅ 文本块（中文）可选：title/subtitle
 * ✅ ratio 白名单校验，避免传错被接口吞
 *
 * 输出：
 * {
 *   ...base,
 *   ...j,
 *   callbackUrl,
 *   request_body
 * }
 */

function s(v) { return v == null ? "" : String(v); }

function buildExactTextBlock({ title, subtitle }) {
  const lines = [];
  lines.push(`[EXACT_TEXT_BLOCKS]`);
  if (title) lines.push(`TITLE: "${title}"`);
  if (subtitle) lines.push(`SUBTITLE: "${subtitle}"`);
  lines.push(`[/EXACT_TEXT_BLOCKS]`);
  return lines.join("\n");
}

function buildTextRules() {
  return [
    `Render EXACT Chinese text as provided. Do NOT change any character.`,
    `Do NOT add extra text.`,
    `Text must be sharp, high-contrast, legible on mobile; no blur; no broken strokes.`,
    `Keep generous margins; do not overlap; avoid clutter.`,
  ].join(" ");
}

function normalizeRatio(ratio) {
  const allowed = new Set(["1:1","3:2","2:3","3:4","4:3","4:5","5:4","9:16","16:9","21:9"]);
  const r = s(ratio).trim();
  return allowed.has(r) ? r : "3:4";
}

function removeEmptyLines(str) {
  return s(str)
    .split("\n")
    .map(x => x.trim())
    .filter(Boolean)
    .join("\n");
}

function buildFinalPrompt({ promptBase, title, subtitle, personDesc, productDesc }) {
  const base = s(promptBase).trim();
  const t = s(title).trim();
  const st = s(subtitle).trim();

  // ✅ 去场景化：不固定地点/光线/时间
  const sceneAgnosticRules = [
    `Scene-agnostic: do NOT mention any specific location, background, time of day, sunlight, golden hour, or lighting setup.`,
    `Use a clean neutral background that can fit any context.`,
    `Do NOT mention camera terms (selfie, close-up, lens, bokeh, etc.).`,
  ].join(" ");

  // ✅（可选）把你分析的“人物特征/产品描述”塞进 prompt，增强一致性
  const pDesc = s(personDesc).trim();
  const prDesc = s(productDesc).trim();
  const consistencyHint = removeEmptyLines([
    pDesc ? `PERSON (reference): ${pDesc}` : "",
    prDesc ? `PRODUCT (reference): ${prDesc}` : "",
    `Maintain identity consistency for the person across generations (face, hair, skin finish, accessories).`,
    `Maintain product visual consistency (shape, color, materials, key details).`,
  ].join("\n"));

  // ✅ 字体块（可选）
  const exactBlock = (t || st) ? buildExactTextBlock({ title: t, subtitle: st }) : "";
  const layoutHint = (t || st)
    ? `Poster layout with clean typography hierarchy; place text in a clear block with generous margins.`
    : "";

  const avoid = [
    `Avoid: wrong Chinese characters, missing strokes, extra text, English letters, garbled words, watermark, logo, UI, low resolution, cluttered layout, overlapping text, distorted characters.`,
  ].join(" ");

  return [
    base,
    consistencyHint,
    sceneAgnosticRules,
    (t || st) ? buildTextRules() : "",
    layoutHint,
    avoid,
    exactBlock
  ].filter(Boolean).join("\n\n");
}

/** 把 base64 塞进 parts（兼容 data:xxx;base64, 前缀） */
function pushInline(parts, { b64, mimeType, label }) {
  const raw = s(b64).trim();
  if (!raw) return;
  const cleanB64 = raw.replace(/^data:.*;base64,/, "").trim();
  parts.push({ text: label }); // 轻量标注，不是场景描述
  parts.push({
    inline_data: {
      mime_type: s(mimeType).trim() || "image/jpeg",
      data: cleanB64,
    }
  });
}

const j = $json || {};
const base = $("准备数据").first()?.json || {};

const promptBase = s(base.prompt).trim();
if (!promptBase) throw new Error("缺少 prompt（准备数据.prompt）");

const ratio = normalizeRatio(base.ratio || "3:4");
const title = s(base.title).trim();
const subtitle = s(base.subtitle).trim();

// 你表里的字段（可选增强一致性）
const personDesc = s(base["人物特征"] || base.person_desc || "").trim();
const productDesc = s(base["产品描述及卖点"] || base.product_desc || "").trim();

// ✅ 读取两张参考图（优先 person/product 字段；兜底旧字段）
const person_b64  = s(j.person_image_b64 || "").trim();
const person_mime = s(j.person_mime_type || "").trim() || "image/jpeg";

const prod_b64    = s(j.product_image_b64 || "").trim();
const prod_mime   = s(j.product_mime_type || "").trim() || "image/jpeg";

// 兜底：如果你还没改字段，就用旧 image_b64/mime_type
const legacy_b64  = s(j.image_b64 || "").trim();
const legacy_mime = s(j.mime_type || "").trim() || "image/jpeg";

// 组 prompt
const finalPrompt = buildFinalPrompt({
  promptBase,
  title,
  subtitle,
  personDesc,
  productDesc,
});

// parts：先放文本，再放参考图
const parts = [{ text: finalPrompt }];

// ✅ 两图输入：加轻量 label，告诉模型哪张是什么（不涉及场景）
if (person_b64) {
  pushInline(parts, { b64: person_b64, mimeType: person_mime, label: "REFERENCE_IMAGE_1: PERSON" });
}
if (prod_b64) {
  pushInline(parts, { b64: prod_b64, mimeType: prod_b64 ? prod_mime : prod_mime, label: "REFERENCE_IMAGE_2: PRODUCT" });
}

// ✅ 如果没有 person/product 字段，尝试 legacy（只放一次，避免重复）
if (!person_b64 && !prod_b64 && legacy_b64) {
  pushInline(parts, { b64: legacy_b64, mimeType: legacy_mime, label: "REFERENCE_IMAGE: INPUT" });
}

// ⚠️ 强制要图片：只要 IMAGE，避免只回文本
const request_body = {
  contents: [{ role: "user", parts }],
  generationConfig: {
    responseModalities: ["IMAGE"],
    imageConfig: { aspectRatio: ratio },
  }
};

return {
  json: {
    ...base,
    ...j,
    request_body,
  }
};

/**
 * 云雾 / Gemini generateContent 响应 -> n8n binary
 *
 * 兼容常见返回路径：
 * - candidates[0].content.parts[*].inline_data.data
 * - candidates[0].content.parts[*].inlineData.data
 * - candidates[0].content.parts[*].fileData（如果有）
 * - data / body 包裹（httpRequest fullResponse 有时会包在 body）
 *
 * 输出：
 * - binary.data.data = base64（无 data: 前缀）
 * - binary.data.mimeType = image/png|image/jpeg
 * - binary.data.fileName = knowledge_card_{image_index}.png
 */

function unwrapRoot(x) {
  // 兼容 httpRequest fullResponse：{ body, headers, statusCode... }
  if (x && typeof x === "object" && x.body && typeof x.body === "object") return x.body;
  return x;
}

function getByPath(obj, path) {
  try {
    return path.split(".").reduce((acc, k) => (acc == null ? undefined : acc[k]), obj);
  } catch {
    return undefined;
  }
}

function findInlineImageParts(root) {
  const candidates = root?.candidates;
  if (!Array.isArray(candidates) || !candidates.length) return [];

  const parts = candidates?.[0]?.content?.parts;
  if (!Array.isArray(parts)) return [];

  // 找到带 inline_data/inlineData 的 part
  const imgs = [];
  for (const p of parts) {
    const inline = p?.inline_data || p?.inlineData;
    if (inline?.data) {
      imgs.push({
        b64: inline.data,
        mimeType: inline.mime_type || inline.mimeType || "image/png",
      });
      continue;
    }
    // 有些实现是 fileData（不一定是 base64）
    const fd = p?.fileData;
    if (fd?.fileUri) {
      imgs.push({
        fileUri: fd.fileUri,
        mimeType: fd.mimeType || "image/png",
      });
    }
  }
  return imgs;
}

function stripDataPrefix(b64) {
  // 兼容 data:image/png;base64,xxxx
  return String(b64 || "").replace(/^data:.*;base64,/, "").trim();
}

const raw = $json || {};
const root = unwrapRoot(raw);

// 你前面节点保留了 image_index（如果没有就默认为 1）
const imageIndex = Number(raw.image_index ?? raw.index ?? 1) || 1;

// 1) 从 candidates.parts 找 inline image
let imgs = findInlineImageParts(root);

// 2) 兜底：有些服务把 base64 放在 data / image / output 之类字段（尽量不猜太多，只做常见兜底）
if (!imgs.length) {
  const maybe =
    getByPath(root, "image.data") ||
    getByPath(root, "data.image") ||
    getByPath(root, "output.image") ||
    getByPath(root, "output.data") ||
    null;

  if (maybe && typeof maybe === "string") {
    imgs = [{ b64: maybe, mimeType: "image/png" }];
  }
}

if (!imgs.length) {
  throw new Error("没有在返回体中找到图片数据（inline_data / inlineData）。请检查生图接口实际响应结构。");
}

// 只取第一张（你这个工作流每个 item 对应一张图）
const first = imgs[0];

// 如果是 fileUri（不是 base64），这里直接报错：因为你后面要上传飞书需要真实二进制
if (first.fileUri && !first.b64) {
  throw new Error(
    `返回的是 fileUri（${first.fileUri}）而不是 base64。需要额外一步去下载该文件再转 binary。`
  );
}

const mimeType = first.mimeType || "image/png";
const ext = mimeType.includes("jpeg") || mimeType.includes("jpg") ? "jpg" : "png";
const b64 = stripDataPrefix(first.b64);

if (!b64) throw new Error("图片 base64 为空");

// 组装 n8n binary（重要：data 要是纯 base64，不要带 data:image 前缀）
return {
  json: {
    ...raw,
    mimeType,
    fileName: `knowledge_card_${imageIndex}.${ext}`,
  },
  binary: {
    data: {
      data: b64,
      mimeType,
      fileName: `Product_display_image_${imageIndex}.${ext}`,
    },
  },
};

